t = tiledlayout(fig,1,1); %[output:623ced5b]
ax = nexttile(t); %[output:623ced5b]
%[text] This time, the data is a list of real numbers, not integers.  The option `BinWidth=...` means to use bins of a particular width, and choose the left-most and right-most edges automatically.  Instead, you could specify the left-most and right-most edges explicitly.  For instance, using `BinEdges=0:0.5:60` means to use bins $(0, 0.5), (0.5, 1.0), \\dots$
h = histogram(ax, TimeInSystem, Normalization="probability", BinWidth=5/60); %[output:623ced5b]
%[text] Add titles and labels and such.
%tvals = linspace(0, max(TimeInSystem), 300);
%fw = (mu - lambda) * exp(-(mu - lambda) * tvals);
%plot(ax, tvals, fw * (5/60), 'r', 'LineWidth', 2);
title(ax, "Time in the system"); %[output:623ced5b]
xlabel(ax, "Time"); %[output:623ced5b]
ylabel(ax, "Probability"); %[output:623ced5b]
%[text] Set ranges on the axes.
%ylim(ax, [0, 0.2]);
xlim(ax, [0, nMax]); %[output:623ced5b]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:623ced5b]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:623ced5b]

% histogram for W_q
fig = figure(); %[output:84c72581]
t = tiledlayout(fig,1,1); %[output:84c72581]
ax = nexttile(t); %[output:84c72581]
TimeWaiting = WaitingInSystemSamples;
